export type Cell = [number, number];

function countNeighbors(cell: Cell, liveCells: Cell[]): number {
  const [x, y] = cell;
  return liveCells.filter(
    ([nx, ny]) => !(nx === x && ny === y) && Math.abs(nx - x) <= 1 && Math.abs(ny - y) <= 1
  ).length;
}

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const survivors = liveCells.filter((cell) => {
    const neighborCount = countNeighbors(cell, liveCells);
    return neighborCount === 2 || neighborCount === 3;
  });

  const deadCandidates = new Map<string, Cell>();
  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx;
        const ny = y + dy;
        const key = `${nx},${ny}`;
        if (!liveCells.some(([lx, ly]) => lx === nx && ly === ny)) {
          deadCandidates.set(key, [nx, ny]);
        }
      }
    }
  }

  const births = [...deadCandidates.values()].filter(
    (cell) => countNeighbors(cell, liveCells) === 3
  );

  return [...survivors, ...births];
}
```

Review for Simple Design Rule violations or improvements. Consider whether the dead cell lookup via .some() could be replaced by using a Set for O(1) lookup. Keep tests green.

